                function return9204(){
                    var n9204 = false;
                    if(
                        //All conditions are mutually exclusive
                        //Condition 1
                        (("3" == Services.getValue(SelectLetter3.dataBinding)||
                        "4" == Services.getValue(SelectLetter3.dataBinding))&&
             
                        Salutation.isEnabled())||
                        
                        //Condition  2
                        ("3" == Services.getValue(SelectLetter3.dataBinding) &&
                        PayableOrderSent.isEnabled())||
                        
                        // Condition 3
                        DrawnInFavourOf.isEnabled()
                        
                    ){
                        n9204 = true;
                    }
                    return n9204;
                }

Javascript.validate:
			//Validation: only numeric characters allowed and two decimal places.
			//Error message: Currency amounts must be in the format of 0.00.
			//Max length: 999999.99		     
            var value = Services.getValue(PayableOrderAmount.dataBinding);      
          	var maxVal = 999999.99;         
          	var err = null;
          
          	if( '0.00 ' != value )
          	{   err = validateCurrencyValue(value, maxVal);
              if( null == err)
              { 
                var returnVal = WPU.formatToTwoDP(value);
                Services.setValue(PayableOrderAmount.dataBinding, returnVal);
              } 
          	}
          	return err;

Javascript.transformToModel:

  if( null == value || "" == value )
  {  return "0.00 ";
  }
  else
  { return value;
  }
